#!/usr/bin/env python3
"""Unified operational CLI for CasinoShiz.Infrastructure.

Host provisioning remains in Ansible. Argo CD/Helm/Kustomize remain declarative.
This CLI replaces repository-level shell orchestration with one entry point.
Container commands embedded in Kubernetes Jobs may still use /bin/sh.
"""
from __future__ import annotations

import argparse
import os
import subprocess
import sys
import tempfile
from pathlib import Path
from typing import NoReturn

ROOT = Path(__file__).resolve().parents[1]

SCRIPTS = {'cluster-status.sh': {'interpreter': 'bash', 'body': 'set -euo pipefail\n\necho "== Nodes =="\nkubectl get nodes -o wide\n\necho\necho "== Argo CD =="\nif command -v kubectl >/dev/null 2>&1; then\n  kubectl get applications -n argocd\nelse\n  echo "Argo CD applications are not available"\nfi\n\necho\necho "== Workloads =="\nkubectl get deployments,statefulsets -A\n\necho\necho "== Pods not Running or Completed =="\nkubectl get pods -A \\\n  --field-selector=status.phase!=Running,status.phase!=Succeeded \\\n  || true\n\necho\necho "== PVCs =="\nkubectl get pvc -A\n\necho\necho "== Ingresses =="\nkubectl get ingress -A\n\necho\necho "== Certificates =="\nkubectl get certificates -A 2>/dev/null || true\n\necho\necho "== Data Jobs =="\nkubectl get cronjobs,jobs -n data\n\necho\necho "== Recent warning events =="\nkubectl get events -A \\\n  --field-selector=type=Warning \\\n  --sort-by=.lastTimestamp \\\n  | tail -n 50\n'}, 'local-cluster-create.sh': {'interpreter': 'bash', 'body': 'set -euo pipefail\n\ncluster="${K3D_CLUSTER_NAME:-casinoshiz-local}"\nregistry="k3d-casinoshiz-registry.localhost"\nregistry_port="${K3D_REGISTRY_PORT:-5005}"\n\nif ! docker info >/dev/null 2>&1; then\n  echo "Docker daemon is not available." >&2\n  exit 1\nfi\n\nif ! k3d registry list | grep -q "${registry}"; then\n  k3d registry create casinoshiz-registry.localhost \\\n    --port "${registry_port}"\nfi\n\nif ! k3d cluster list | grep -q "^${cluster}[[:space:]]"; then\n  k3d cluster create "${cluster}" \\\n    --servers 1 \\\n    --agents 0 \\\n    --registry-use "${registry}:${registry_port}" \\\n    --port "8080:80@loadbalancer" \\\n    --port "8443:443@loadbalancer" \\\n    --wait\nfi\n\nkubectl config use-context "k3d-${cluster}"\nkubectl get nodes\n'}, 'local-cluster-delete.sh': {'interpreter': 'bash', 'body': 'set -euo pipefail\n\ncluster="${K3D_CLUSTER_NAME:-casinoshiz-local}"\n\nk3d cluster delete "${cluster}" || true\n\nif [[ "${DELETE_LOCAL_REGISTRY:-false}" == "true" ]]; then\n  k3d registry delete casinoshiz-registry.localhost || true\nfi\n'}, 'local-argocd-bootstrap.sh': {'interpreter': 'bash', 'body': 'set -euo pipefail\n\nage_key_file="${SOPS_AGE_KEY_FILE:-$HOME/.config/sops/age/keys.txt}"\n[[ -f "${age_key_file}" ]] || { echo "Age key not found: ${age_key_file}" >&2; exit 1; }\n\nkubectl apply -f argocd/namespace.yaml\nkubectl create secret generic sops-age \\\n  --namespace=argocd \\\n  --from-file=keys.txt="${age_key_file}" \\\n  --dry-run=client -o yaml | kubectl apply -f -\nkubectl apply -f argocd/cmp-plugin.yaml\nhelm repo add argo https://argoproj.github.io/argo-helm --force-update\nhelm repo update\nhelm upgrade --install argocd argo/argo-cd \\\n  --namespace argocd --create-namespace \\\n  --values argocd/values.yaml \\\n  --wait --timeout 15m\nkubectl apply -f argocd/project.yaml\nkubectl apply -f argocd/root-local.yaml\nkubectl get applications -n argocd\n'}, 'local-image-push.sh': {'interpreter': 'bash', 'body': 'set -euo pipefail\n\nif (($# != 2)); then\n  echo "Usage: $0 <source-image:tag> <target-repository>" >&2\n  echo "Example: $0 casinoshiz-backend:latest casinoshiz-backend" >&2\n  exit 2\nfi\n\nsource_image="$1"\ntarget_repository="$2"\nhost_registry="${LOCAL_REGISTRY_HOST:-localhost:5005}"\ntarget="${host_registry}/${target_repository}:local"\n\ndocker image inspect "${source_image}" >/dev/null\ndocker tag "${source_image}" "${target}"\ndocker push "${target}"\n\necho "Pushed ${target}"\n'}, 'manual-backup.sh': {'interpreter': 'bash', 'body': 'set -euo pipefail\n\ntimestamp="$(date +%s)"\ncronjobs=(\n  postgres-backup\n  redis-backup\n  clickhouse-backup\n  minio-backup\n)\n\njobs=()\n\nfor cronjob in "${cronjobs[@]}"; do\n  job="${cronjob}-manual-${timestamp}"\n  kubectl create job \\\n    --from="cronjob/${cronjob}" \\\n    "$job" \\\n    -n data\n  jobs+=("$job")\ndone\n\nfor job in "${jobs[@]}"; do\n  kubectl wait \\\n    --for=condition=complete \\\n    "job/${job}" \\\n    -n data \\\n    --timeout=30m\n\n  kubectl logs \\\n    "job/${job}" \\\n    -n data\ndone\n\necho "All manual backup Jobs completed."\n'}, 'post-deploy-check.sh': {'interpreter': 'bash', 'body': 'set -euo pipefail\n\nwait_timeout="${WAIT_TIMEOUT:-300s}"\n\necho "Checking Argo CD..."\nif command -v kubectl >/dev/null 2>&1; then\n  kubectl get applications -n argocd\nfi\n\necho "Waiting for data StatefulSets..."\nfor statefulset in postgres redis clickhouse minio; do\n  kubectl rollout status "statefulset/${statefulset}" \\\n    -n data \\\n    --timeout="${wait_timeout}"\ndone\n\necho "Waiting for CasinoShiz Deployments..."\nwhile IFS= read -r deployment; do\n  kubectl rollout status "$deployment" \\\n    -n casinoshiz \\\n    --timeout="${wait_timeout}"\ndone < <(kubectl get deployments -n casinoshiz -o name)\n\necho "Checking PVCs..."\nkubectl get pvc -A\n\nunbound="$(\n  kubectl get pvc -A \\\n    -o jsonpath=\'{range .items[?(@.status.phase!="Bound")]}{.metadata.namespace}/{.metadata.name}{"\\n"}{end}\'\n)"\nif [[ -n "$unbound" ]]; then\n  printf \'Unbound PVCs:\\n%s\\n\' "$unbound" >&2\n  exit 1\nfi\n\necho "Checking certificates..."\nkubectl get certificates -A\n\necho "Checking ingresses..."\nkubectl get ingress -A\n\necho "Checking backup CronJobs..."\nkubectl get cronjobs -n data\n\necho "Checking observability..."\nkubectl get pods -n monitoring\nkubectl get pods -n observability\n\necho "Checking application health from inside the cluster..."\nfor service in telegram-bff admin-bff rest-api; do\n  kubectl run "health-${service}-$(date +%s)" \\\n    --rm \\\n    --restart=Never \\\n    --image=curlimages/curl:8.12.1 \\\n    -n casinoshiz \\\n    -- \\\n    -fsS "http://${service}.casinoshiz.svc.cluster.local:8080/health/ready"\ndone\n\necho "Post-deployment checks passed."\n'}, 'preflight.sh': {'interpreter': 'bash', 'body': 'set -euo pipefail\n\nrequired=(git helm kustomize kubectl go-task ansible-playbook)\nmissing=()\n\nfor tool in "${required[@]}"; do\n  if ! command -v "$tool" >/dev/null 2>&1; then\n    missing+=("$tool")\n  fi\ndone\n\nif ((${#missing[@]} > 0)); then\n  printf \'Missing required tools: %s\\n\' "${missing[*]}" >&2\n  exit 1\nfi\n\nif [[ ! -f Taskfile.yml ]]; then\n  echo "Run this script from the repository root." >&2\n  exit 1\nfi\n\necho "Validating repository..."\ngo-task clean\ngo-task validate\n\necho "Checking unresolved placeholders..."\nplaceholders="$(git grep -n CHANGE_ME || true)"\nif [[ -n "$placeholders" ]]; then\n  printf \'%s\\n\' "$placeholders"\n  echo "Unresolved CHANGE_ME values remain." >&2\n  exit 1\nfi\n\necho "Checking repository state..."\nif [[ -n "$(git status --porcelain)" ]]; then\n  git status --short\n  echo "Working tree is not clean." >&2\n  exit 1\nfi\n\necho "Checking Kubernetes access..."\nkubectl version --client\nkubectl cluster-info\nkubectl get nodes\n\necho "Preflight passed."\n'}, 'restore-clickhouse.sh': {'interpreter': 'sh', 'body': 'set -eu\n\nset -eu\n\nNAMESPACE="${NAMESPACE:-data}"\nBACKUP_PVC="${BACKUP_PVC:-data-backups}"\n\ndie() {\n  printf \'error: %s\n\' "$*" >&2\n  exit 1\n}\n\ninfo() {\n  printf \'==> %s\n\' "$*"\n}\n\nrequire_command() {\n  command -v "$1" >/dev/null 2>&1 || die "missing command: $1"\n}\n\nlatest_backup_dir() {\n  kind="$1"\n  kubectl -n "$NAMESPACE" run "backup-lister-$$" \\\n    --restart=Never \\\n    --image=alpine:3.22 \\\n    --overrides="$(\n      cat <<JSON\n{\n  "spec": {\n    "containers": [{\n      "name": "lister",\n      "image": "alpine:3.22",\n      "command": ["/bin/sh", "-ec", "find /backup/$kind -mindepth 1 -maxdepth 1 -type d -printf \'%f\\n\' | sort | tail -n 1"],\n      "volumeMounts": [{"name": "backups", "mountPath": "/backup"}]\n    }],\n    "volumes": [{"name": "backups", "persistentVolumeClaim": {"claimName": "$BACKUP_PVC"}}]\n  }\n}\nJSON\n    )" >/dev/null\n\n  kubectl -n "$NAMESPACE" wait \\\n    --for=jsonpath=\'{.status.phase}\'=Succeeded \\\n    "pod/backup-lister-$$" \\\n    --timeout=90s >/dev/null\n\n  result="$(kubectl -n "$NAMESPACE" logs "pod/backup-lister-$$")"\n  kubectl -n "$NAMESPACE" delete pod "backup-lister-$$" --wait=false >/dev/null 2>&1 || true\n  [ -n "$result" ] || die "no backup directories found for $kind"\n  printf \'%s\n\' "$result"\n}\n\nwait_job() {\n  job="$1"\n  timeout="${2:-600s}"\n  kubectl -n "$NAMESPACE" wait \\\n    --for=condition=complete \\\n    "job/$job" \\\n    --timeout="$timeout" || {\n      kubectl -n "$NAMESPACE" logs "job/$job" --all-containers=true || true\n      return 1\n    }\n  kubectl -n "$NAMESPACE" logs "job/$job" --all-containers=true\n}\n\n\nrequire_command kubectl\n\nBACKUP="${BACKUP:-latest}"\nSOURCE_DATABASE="${SOURCE_DATABASE:-cazinoshiz}"\nTARGET_DATABASE="${TARGET_DATABASE:-}"\nDROP_TARGET="${DROP_TARGET:-false}"\nKEEP_JOB="${KEEP_JOB:-false}"\n\nusage() {\n  cat <<\'EOF\'\nUsage:\n  restore-clickhouse.sh [options]\n\nOptions:\n  --backup NAME          ClickHouse Disk backup name or "latest".\n  --source-db NAME       Source database stored in backup.\n  --target-db NAME       Target database. Defaults to a timestamped restore DB.\n  --drop-target          Drop an existing target database.\n  --keep-job             Keep the Job after completion.\nEOF\n}\n\nwhile [ "$#" -gt 0 ]; do\n  case "$1" in\n    --backup) BACKUP="$2"; shift 2 ;;\n    --source-db) SOURCE_DATABASE="$2"; shift 2 ;;\n    --target-db) TARGET_DATABASE="$2"; shift 2 ;;\n    --drop-target) DROP_TARGET=true; shift ;;\n    --keep-job) KEEP_JOB=true; shift ;;\n    -h|--help) usage; exit 0 ;;\n    *) die "unknown argument: $1" ;;\n  esac\ndone\n\nfor value in "$SOURCE_DATABASE" "${TARGET_DATABASE:-placeholder}"; do\n  case "$value" in\n    *[!a-zA-Z0-9_]*|\'\') die "invalid database identifier: $value" ;;\n  esac\ndone\n\nif [ "$BACKUP" = latest ]; then\n  BACKUP="$(latest_backup_dir clickhouse)"\nfi\n\nif [ -z "$TARGET_DATABASE" ]; then\n  TARGET_DATABASE="${SOURCE_DATABASE}_restore_$(date -u +%Y%m%d%H%M%S)"\nfi\n\nJOB="clickhouse-restore-$(date +%s)"\nDROP_QUERY=""\nif [ "$DROP_TARGET" = true ]; then\n  DROP_QUERY="DROP DATABASE IF EXISTS \\\\\\`$TARGET_DATABASE\\\\\\`;"\nfi\n\ninfo "Restoring ClickHouse $SOURCE_DATABASE from $BACKUP into $TARGET_DATABASE"\n\ncat <<YAML | kubectl apply -f -\napiVersion: batch/v1\nkind: Job\nmetadata:\n  name: $JOB\n  namespace: $NAMESPACE\nspec:\n  backoffLimit: 0\n  ttlSecondsAfterFinished: 3600\n  template:\n    spec:\n      restartPolicy: Never\n      containers:\n        - name: restore\n          image: clickhouse/clickhouse-server:24.8-alpine\n          env:\n            - name: CLICKHOUSE_PASSWORD\n              valueFrom:\n                secretKeyRef:\n                  name: data-secrets\n                  key: clickhouse-password\n          command:\n            - /bin/sh\n            - -ec\n            - |\n              client() {\n                clickhouse-client \\\n                  --host clickhouse.data.svc.cluster.local \\\n                  --password "\\$CLICKHOUSE_PASSWORD" \\\n                  --multiquery \\\n                  --query "\\$1"\n              }\n\n              client "$DROP_QUERY"\n\n              existing="\\$(clickhouse-client \\\n                --host clickhouse.data.svc.cluster.local \\\n                --password "\\$CLICKHOUSE_PASSWORD" \\\n                --query "EXISTS DATABASE \\\\\\`$TARGET_DATABASE\\\\\\`")"\n              test "\\$existing" = 0 || {\n                echo "target database already exists: $TARGET_DATABASE" >&2\n                exit 1\n              }\n\n              client "RESTORE DATABASE \\\\\\`$SOURCE_DATABASE\\\\\\`\n                AS \\\\\\`$TARGET_DATABASE\\\\\\`\n                FROM Disk(\'backup\', \'$BACKUP\')"\n\n              tables="\\$(clickhouse-client \\\n                --host clickhouse.data.svc.cluster.local \\\n                --password "\\$CLICKHOUSE_PASSWORD" \\\n                --query "SELECT count() FROM system.tables WHERE database = \'$TARGET_DATABASE\'")"\n              test "\\$tables" -gt 0\n              echo "restored database=$TARGET_DATABASE tables=\\$tables"\nYAML\n\nwait_job "$JOB" 1800s\n\nif [ "$KEEP_JOB" != true ]; then\n  kubectl -n "$NAMESPACE" delete job "$JOB" --wait=false >/dev/null\nfi\n\ninfo "ClickHouse restore completed: $TARGET_DATABASE"\n'}, 'restore-minio.sh': {'interpreter': 'sh', 'body': 'set -eu\n\nset -eu\n\nNAMESPACE="${NAMESPACE:-data}"\nBACKUP_PVC="${BACKUP_PVC:-data-backups}"\n\ndie() {\n  printf \'error: %s\n\' "$*" >&2\n  exit 1\n}\n\ninfo() {\n  printf \'==> %s\n\' "$*"\n}\n\nrequire_command() {\n  command -v "$1" >/dev/null 2>&1 || die "missing command: $1"\n}\n\nlatest_backup_dir() {\n  kind="$1"\n  kubectl -n "$NAMESPACE" run "backup-lister-$$" \\\n    --restart=Never \\\n    --image=alpine:3.22 \\\n    --overrides="$(\n      cat <<JSON\n{\n  "spec": {\n    "containers": [{\n      "name": "lister",\n      "image": "alpine:3.22",\n      "command": ["/bin/sh", "-ec", "find /backup/$kind -mindepth 1 -maxdepth 1 -type d -printf \'%f\\n\' | sort | tail -n 1"],\n      "volumeMounts": [{"name": "backups", "mountPath": "/backup"}]\n    }],\n    "volumes": [{"name": "backups", "persistentVolumeClaim": {"claimName": "$BACKUP_PVC"}}]\n  }\n}\nJSON\n    )" >/dev/null\n\n  kubectl -n "$NAMESPACE" wait \\\n    --for=jsonpath=\'{.status.phase}\'=Succeeded \\\n    "pod/backup-lister-$$" \\\n    --timeout=90s >/dev/null\n\n  result="$(kubectl -n "$NAMESPACE" logs "pod/backup-lister-$$")"\n  kubectl -n "$NAMESPACE" delete pod "backup-lister-$$" --wait=false >/dev/null 2>&1 || true\n  [ -n "$result" ] || die "no backup directories found for $kind"\n  printf \'%s\n\' "$result"\n}\n\nwait_job() {\n  job="$1"\n  timeout="${2:-600s}"\n  kubectl -n "$NAMESPACE" wait \\\n    --for=condition=complete \\\n    "job/$job" \\\n    --timeout="$timeout" || {\n      kubectl -n "$NAMESPACE" logs "job/$job" --all-containers=true || true\n      return 1\n    }\n  kubectl -n "$NAMESPACE" logs "job/$job" --all-containers=true\n}\n\n\nrequire_command kubectl\n\nBACKUP="${BACKUP:-latest}"\nSOURCE_BUCKET="${SOURCE_BUCKET:-}"\nTARGET_BUCKET="${TARGET_BUCKET:-}"\nOVERWRITE="${OVERWRITE:-false}"\nKEEP_JOB="${KEEP_JOB:-false}"\n\nusage() {\n  cat <<\'EOF\'\nUsage:\n  restore-minio.sh --bucket NAME [options]\n\nOptions:\n  --backup NAME          Backup directory or "latest".\n  --bucket NAME          Source bucket directory inside the backup.\n  --target-bucket NAME   Destination bucket. Defaults to a timestamped name.\n  --overwrite            Allow mirroring into an existing target bucket.\n  --keep-job             Keep the Job.\n\nBy default this restores into a new bucket and does not overwrite production.\nEOF\n}\n\nwhile [ "$#" -gt 0 ]; do\n  case "$1" in\n    --backup) BACKUP="$2"; shift 2 ;;\n    --bucket) SOURCE_BUCKET="$2"; shift 2 ;;\n    --target-bucket) TARGET_BUCKET="$2"; shift 2 ;;\n    --overwrite) OVERWRITE=true; shift ;;\n    --keep-job) KEEP_JOB=true; shift ;;\n    -h|--help) usage; exit 0 ;;\n    *) die "unknown argument: $1" ;;\n  esac\ndone\n\n[ -n "$SOURCE_BUCKET" ] || die "--bucket is required"\n\nif [ "$BACKUP" = latest ]; then\n  BACKUP="$(latest_backup_dir minio)"\nfi\n\nif [ -z "$TARGET_BUCKET" ]; then\n  TARGET_BUCKET="${SOURCE_BUCKET}-restore-$(date -u +%Y%m%d%H%M%S)"\nfi\n\nJOB="minio-restore-$(date +%s)"\nMIRROR_FLAG=""\nif [ "$OVERWRITE" = true ]; then\n  MIRROR_FLAG="--overwrite"\nfi\n\ninfo "Restoring MinIO bucket $SOURCE_BUCKET from $BACKUP into $TARGET_BUCKET"\n\ncat <<YAML | kubectl apply -f -\napiVersion: batch/v1\nkind: Job\nmetadata:\n  name: $JOB\n  namespace: $NAMESPACE\nspec:\n  backoffLimit: 0\n  ttlSecondsAfterFinished: 3600\n  template:\n    spec:\n      restartPolicy: Never\n      containers:\n        - name: restore\n          image: minio/mc:RELEASE.2025-08-13T08-35-41Z\n          env:\n            - name: MINIO_ROOT_USER\n              valueFrom:\n                secretKeyRef:\n                  name: data-secrets\n                  key: minio-root-user\n            - name: MINIO_ROOT_PASSWORD\n              valueFrom:\n                secretKeyRef:\n                  name: data-secrets\n                  key: minio-root-password\n          command:\n            - /bin/sh\n            - -ec\n            - |\n              src="/backup/minio/$BACKUP/$SOURCE_BUCKET"\n              test -d "\\$src"\n\n              mc alias set target \\\n                http://minio.data.svc.cluster.local:9000 \\\n                "\\$MINIO_ROOT_USER" \\\n                "\\$MINIO_ROOT_PASSWORD"\n\n              if mc stat "target/$TARGET_BUCKET" >/dev/null 2>&1; then\n                test "$OVERWRITE" = true || {\n                  echo "target bucket already exists: $TARGET_BUCKET" >&2\n                  exit 1\n                }\n              else\n                mc mb "target/$TARGET_BUCKET"\n              fi\n\n              mc mirror $MIRROR_FLAG "\\$src" "target/$TARGET_BUCKET"\n\n              local_count="\\$(find "\\$src" -type f | wc -l | tr -d \' \')"\n              remote_count="\\$(mc find "target/$TARGET_BUCKET" --type f | wc -l | tr -d \' \')"\n              test "\\$remote_count" -ge "\\$local_count"\n              echo "restored bucket=$TARGET_BUCKET objects=\\$remote_count"\n          volumeMounts:\n            - name: backups\n              mountPath: /backup\n              readOnly: true\n      volumes:\n        - name: backups\n          persistentVolumeClaim:\n            claimName: $BACKUP_PVC\nYAML\n\nwait_job "$JOB" 1800s\n\nif [ "$KEEP_JOB" != true ]; then\n  kubectl -n "$NAMESPACE" delete job "$JOB" --wait=false >/dev/null\nfi\n\ninfo "MinIO restore completed: $TARGET_BUCKET"\n'}, 'restore-postgres.sh': {'interpreter': 'sh', 'body': 'set -eu\n\nset -eu\n\nNAMESPACE="${NAMESPACE:-data}"\nBACKUP_PVC="${BACKUP_PVC:-data-backups}"\n\ndie() {\n  printf \'error: %s\n\' "$*" >&2\n  exit 1\n}\n\ninfo() {\n  printf \'==> %s\n\' "$*"\n}\n\nrequire_command() {\n  command -v "$1" >/dev/null 2>&1 || die "missing command: $1"\n}\n\nlatest_backup_dir() {\n  kind="$1"\n  kubectl -n "$NAMESPACE" run "backup-lister-$$" \\\n    --restart=Never \\\n    --image=alpine:3.22 \\\n    --overrides="$(\n      cat <<JSON\n{\n  "spec": {\n    "containers": [{\n      "name": "lister",\n      "image": "alpine:3.22",\n      "command": ["/bin/sh", "-ec", "find /backup/$kind -mindepth 1 -maxdepth 1 -type d -printf \'%f\\n\' | sort | tail -n 1"],\n      "volumeMounts": [{"name": "backups", "mountPath": "/backup"}]\n    }],\n    "volumes": [{"name": "backups", "persistentVolumeClaim": {"claimName": "$BACKUP_PVC"}}]\n  }\n}\nJSON\n    )" >/dev/null\n\n  kubectl -n "$NAMESPACE" wait \\\n    --for=jsonpath=\'{.status.phase}\'=Succeeded \\\n    "pod/backup-lister-$$" \\\n    --timeout=90s >/dev/null\n\n  result="$(kubectl -n "$NAMESPACE" logs "pod/backup-lister-$$")"\n  kubectl -n "$NAMESPACE" delete pod "backup-lister-$$" --wait=false >/dev/null 2>&1 || true\n  [ -n "$result" ] || die "no backup directories found for $kind"\n  printf \'%s\n\' "$result"\n}\n\nwait_job() {\n  job="$1"\n  timeout="${2:-600s}"\n  kubectl -n "$NAMESPACE" wait \\\n    --for=condition=complete \\\n    "job/$job" \\\n    --timeout="$timeout" || {\n      kubectl -n "$NAMESPACE" logs "job/$job" --all-containers=true || true\n      return 1\n    }\n  kubectl -n "$NAMESPACE" logs "job/$job" --all-containers=true\n}\n\n\nrequire_command kubectl\n\nBACKUP="${BACKUP:-latest}"\nDATABASE="${DATABASE:-backend}"\nTARGET_DATABASE="${TARGET_DATABASE:-}"\nDROP_TARGET="${DROP_TARGET:-false}"\nKEEP_JOB="${KEEP_JOB:-false}"\n\nusage() {\n  cat <<\'EOF\'\nUsage:\n  restore-postgres.sh [options]\n\nOptions:\n  --backup NAME          Backup directory name or "latest".\n  --database NAME        Source dump name, default: backend.\n  --target NAME          Target database. Default: <database>_restore_<timestamp>.\n  --drop-target          Drop an existing target database before restore.\n  --keep-job             Keep the Kubernetes Job after completion.\n\nEnvironment:\n  NAMESPACE=data\n  BACKUP_PVC=data-backups\n\nThe production database is never overwritten unless --target explicitly names it.\nEOF\n}\n\nwhile [ "$#" -gt 0 ]; do\n  case "$1" in\n    --backup) BACKUP="$2"; shift 2 ;;\n    --database) DATABASE="$2"; shift 2 ;;\n    --target) TARGET_DATABASE="$2"; shift 2 ;;\n    --drop-target) DROP_TARGET=true; shift ;;\n    --keep-job) KEEP_JOB=true; shift ;;\n    -h|--help) usage; exit 0 ;;\n    *) die "unknown argument: $1" ;;\n  esac\ndone\n\ncase "$DATABASE" in\n  *[!a-zA-Z0-9_]*|\'\') die "invalid database name: $DATABASE" ;;\nesac\n\nif [ "$BACKUP" = latest ]; then\n  BACKUP="$(latest_backup_dir postgres)"\nfi\n\nif [ -z "$TARGET_DATABASE" ]; then\n  TARGET_DATABASE="${DATABASE}_restore_$(date -u +%Y%m%d%H%M%S)"\nfi\n\ncase "$TARGET_DATABASE" in\n  *[!a-zA-Z0-9_]*|\'\') die "invalid target database name: $TARGET_DATABASE" ;;\nesac\n\nJOB="postgres-restore-$(date +%s)"\nDROP_SQL=""\nif [ "$DROP_TARGET" = true ]; then\n  DROP_SQL="DROP DATABASE IF EXISTS \\"$TARGET_DATABASE\\" WITH (FORCE);"\nfi\n\ninfo "Restoring PostgreSQL $DATABASE from $BACKUP into $TARGET_DATABASE"\n\ncat <<YAML | kubectl apply -f -\napiVersion: batch/v1\nkind: Job\nmetadata:\n  name: $JOB\n  namespace: $NAMESPACE\n  labels:\n    app.kubernetes.io/name: postgres-restore\nspec:\n  backoffLimit: 0\n  ttlSecondsAfterFinished: 3600\n  template:\n    metadata:\n      labels:\n        app.kubernetes.io/name: postgres-restore\n    spec:\n      restartPolicy: Never\n      containers:\n        - name: restore\n          image: postgres:16-alpine\n          env:\n            - name: PGHOST\n              value: postgres.data.svc.cluster.local\n            - name: PGUSER\n              value: postgres\n            - name: PGPASSWORD\n              valueFrom:\n                secretKeyRef:\n                  name: data-secrets\n                  key: postgres-superuser-password\n          command:\n            - /bin/sh\n            - -ec\n            - |\n              backup_dir="/backup/postgres/$BACKUP"\n              dump="\\$backup_dir/$DATABASE.dump"\n              test -s "\\$dump"\n\n              if test -f "\\$backup_dir/SHA256SUMS"; then\n                cd "\\$backup_dir"\n                sha256sum -c SHA256SUMS\n              fi\n\n              psql --dbname=postgres --set=ON_ERROR_STOP=1 <<\'SQL\'\n              $DROP_SQL\nSQL\n\n              exists="\\$(psql --dbname=postgres --tuples-only --no-align \\\n                --command "SELECT 1 FROM pg_database WHERE datname = \'$TARGET_DATABASE\'")"\n              test -z "\\$exists" || {\n                echo "target database already exists: $TARGET_DATABASE" >&2\n                exit 1\n              }\n\n              createdb "$TARGET_DATABASE"\n              pg_restore \\\n                --exit-on-error \\\n                --no-owner \\\n                --no-privileges \\\n                --dbname="$TARGET_DATABASE" \\\n                "\\$dump"\n\n              tables="\\$(psql --dbname="$TARGET_DATABASE" --tuples-only --no-align \\\n                --command "SELECT count(*) FROM pg_catalog.pg_tables WHERE schemaname NOT IN (\'pg_catalog\',\'information_schema\')")"\n              test "\\$tables" -gt 0\n              echo "restored database=$TARGET_DATABASE tables=\\$tables"\n          volumeMounts:\n            - name: backups\n              mountPath: /backup\n              readOnly: true\n      volumes:\n        - name: backups\n          persistentVolumeClaim:\n            claimName: $BACKUP_PVC\nYAML\n\nwait_job "$JOB" 900s\n\nif [ "$KEEP_JOB" != true ]; then\n  kubectl -n "$NAMESPACE" delete job "$JOB" --wait=false >/dev/null\nfi\n\ninfo "PostgreSQL restore completed: $TARGET_DATABASE"\n'}, 'restore-redis.sh': {'interpreter': 'sh', 'body': 'set -eu\n\nset -eu\n\nNAMESPACE="${NAMESPACE:-data}"\nBACKUP_PVC="${BACKUP_PVC:-data-backups}"\n\ndie() {\n  printf \'error: %s\n\' "$*" >&2\n  exit 1\n}\n\ninfo() {\n  printf \'==> %s\n\' "$*"\n}\n\nrequire_command() {\n  command -v "$1" >/dev/null 2>&1 || die "missing command: $1"\n}\n\nlatest_backup_dir() {\n  kind="$1"\n  kubectl -n "$NAMESPACE" run "backup-lister-$$" \\\n    --restart=Never \\\n    --image=alpine:3.22 \\\n    --overrides="$(\n      cat <<JSON\n{\n  "spec": {\n    "containers": [{\n      "name": "lister",\n      "image": "alpine:3.22",\n      "command": ["/bin/sh", "-ec", "find /backup/$kind -mindepth 1 -maxdepth 1 -type d -printf \'%f\\n\' | sort | tail -n 1"],\n      "volumeMounts": [{"name": "backups", "mountPath": "/backup"}]\n    }],\n    "volumes": [{"name": "backups", "persistentVolumeClaim": {"claimName": "$BACKUP_PVC"}}]\n  }\n}\nJSON\n    )" >/dev/null\n\n  kubectl -n "$NAMESPACE" wait \\\n    --for=jsonpath=\'{.status.phase}\'=Succeeded \\\n    "pod/backup-lister-$$" \\\n    --timeout=90s >/dev/null\n\n  result="$(kubectl -n "$NAMESPACE" logs "pod/backup-lister-$$")"\n  kubectl -n "$NAMESPACE" delete pod "backup-lister-$$" --wait=false >/dev/null 2>&1 || true\n  [ -n "$result" ] || die "no backup directories found for $kind"\n  printf \'%s\n\' "$result"\n}\n\nwait_job() {\n  job="$1"\n  timeout="${2:-600s}"\n  kubectl -n "$NAMESPACE" wait \\\n    --for=condition=complete \\\n    "job/$job" \\\n    --timeout="$timeout" || {\n      kubectl -n "$NAMESPACE" logs "job/$job" --all-containers=true || true\n      return 1\n    }\n  kubectl -n "$NAMESPACE" logs "job/$job" --all-containers=true\n}\n\n\nrequire_command kubectl\n\nBACKUP="${BACKUP:-latest}"\nMODE="${MODE:-verify}"\nCONFIRM="${CONFIRM:-}"\nKEEP_JOB="${KEEP_JOB:-false}"\n\nusage() {\n  cat <<\'EOF\'\nUsage:\n  restore-redis.sh [options]\n\nOptions:\n  --backup NAME          Backup directory or "latest".\n  --mode verify          Start an isolated Redis and validate the RDB (default).\n  --mode replace         Replace the production Redis PVC contents.\n  --confirm REPLACE_REDIS\n                        Required with --mode replace.\n  --keep-job             Keep the verification Job.\n\n`replace` scales the Redis StatefulSet to zero, rewrites its PVC and starts it.\nUse only during a maintenance window.\nEOF\n}\n\nwhile [ "$#" -gt 0 ]; do\n  case "$1" in\n    --backup) BACKUP="$2"; shift 2 ;;\n    --mode) MODE="$2"; shift 2 ;;\n    --confirm) CONFIRM="$2"; shift 2 ;;\n    --keep-job) KEEP_JOB=true; shift ;;\n    -h|--help) usage; exit 0 ;;\n    *) die "unknown argument: $1" ;;\n  esac\ndone\n\nif [ "$BACKUP" = latest ]; then\n  BACKUP="$(latest_backup_dir redis)"\nfi\n\ncase "$MODE" in\n  verify)\n    JOB="redis-restore-verify-$(date +%s)"\n    info "Verifying Redis backup $BACKUP in an isolated instance"\n\n    cat <<YAML | kubectl apply -f -\napiVersion: batch/v1\nkind: Job\nmetadata:\n  name: $JOB\n  namespace: $NAMESPACE\nspec:\n  backoffLimit: 0\n  ttlSecondsAfterFinished: 3600\n  template:\n    spec:\n      restartPolicy: Never\n      containers:\n        - name: verify\n          image: redis:7-alpine\n          command:\n            - /bin/sh\n            - -ec\n            - |\n              src="/backup/redis/$BACKUP"\n              test -s "\\$src/dump.rdb"\n              mkdir -p /restore\n              cp "\\$src/dump.rdb" /restore/dump.rdb\n\n              if test -f "\\$src/SHA256SUMS"; then\n                cd "\\$src"\n                sha256sum -c SHA256SUMS || true\n              fi\n\n              redis-check-rdb /restore/dump.rdb\n              redis-server \\\n                --dir /restore \\\n                --dbfilename dump.rdb \\\n                --appendonly no \\\n                --protected-mode no \\\n                --bind 127.0.0.1 \\\n                --daemonize yes\n\n              for attempt in \\$(seq 1 30); do\n                redis-cli -h 127.0.0.1 ping >/dev/null 2>&1 && break\n                sleep 1\n              done\n\n              redis-cli -h 127.0.0.1 ping\n              keys="\\$(redis-cli -h 127.0.0.1 dbsize | tr -d \'\\r\')"\n              echo "verified backup=$BACKUP keys=\\$keys"\n              redis-cli -h 127.0.0.1 shutdown nosave\n          volumeMounts:\n            - name: backups\n              mountPath: /backup\n              readOnly: true\n      volumes:\n        - name: backups\n          persistentVolumeClaim:\n            claimName: $BACKUP_PVC\nYAML\n\n    wait_job "$JOB" 600s\n    if [ "$KEEP_JOB" != true ]; then\n      kubectl -n "$NAMESPACE" delete job "$JOB" --wait=false >/dev/null\n    fi\n    ;;\n\n  replace)\n    [ "$CONFIRM" = REPLACE_REDIS ] || die \\\n      "--mode replace requires --confirm REPLACE_REDIS"\n\n    info "Scaling Redis StatefulSet to zero"\n    kubectl -n "$NAMESPACE" scale statefulset redis --replicas=0\n    kubectl -n "$NAMESPACE" wait \\\n      --for=delete pod/redis-0 \\\n      --timeout=180s || true\n\n    POD="redis-restore-copy-$(date +%s)"\n    info "Replacing production Redis data from backup $BACKUP"\n    cat <<YAML | kubectl apply -f -\napiVersion: v1\nkind: Pod\nmetadata:\n  name: $POD\n  namespace: $NAMESPACE\nspec:\n  restartPolicy: Never\n  containers:\n    - name: restore\n      image: redis:7-alpine\n      command:\n        - /bin/sh\n        - -ec\n        - |\n          src="/backup/redis/$BACKUP"\n          test -s "\\$src/dump.rdb"\n          redis-check-rdb "\\$src/dump.rdb"\n\n          find /redis-data -mindepth 1 -maxdepth 1 -exec rm -rf {} +\n          cp "\\$src/dump.rdb" /redis-data/dump.rdb\n\n          if test -d "\\$src/appendonlydir"; then\n            cp -a "\\$src/appendonlydir" /redis-data/\n          fi\n\n          chown -R 999:999 /redis-data\n          echo "production Redis PVC replaced"\n      volumeMounts:\n        - name: backups\n          mountPath: /backup\n          readOnly: true\n        - name: redis-data\n          mountPath: /redis-data\n  volumes:\n    - name: backups\n      persistentVolumeClaim:\n        claimName: $BACKUP_PVC\n    - name: redis-data\n      persistentVolumeClaim:\n        claimName: data-redis-0\nYAML\n\n    kubectl -n "$NAMESPACE" wait \\\n      --for=jsonpath=\'{.status.phase}\'=Succeeded \\\n      "pod/$POD" \\\n      --timeout=300s || {\n        kubectl -n "$NAMESPACE" logs "$POD" || true\n        die "Redis restore copy failed; StatefulSet remains scaled down"\n      }\n    kubectl -n "$NAMESPACE" logs "$POD"\n    kubectl -n "$NAMESPACE" delete pod "$POD" --wait=false >/dev/null\n\n    info "Starting Redis StatefulSet"\n    kubectl -n "$NAMESPACE" scale statefulset redis --replicas=1\n    kubectl -n "$NAMESPACE" rollout status statefulset/redis --timeout=300s\n    ;;\n\n  *) die "mode must be verify or replace" ;;\nesac\n'}, 'restore-smoke-test.sh': {'interpreter': 'sh', 'body': 'set -eu\n\nSCRIPT_DIR="$(CDPATH= cd -- "$(dirname -- "$0")" && pwd)"\n\nPOSTGRES_DATABASE="${POSTGRES_DATABASE:-backend}"\nCLICKHOUSE_DATABASE="${CLICKHOUSE_DATABASE:-cazinoshiz}"\nMINIO_BUCKET="${MINIO_BUCKET:-}"\n\ncleanup_postgres=""\ncleanup_clickhouse=""\n\ntimestamp="$(date -u +%Y%m%d%H%M%S)"\npg_target="${POSTGRES_DATABASE}_restore_smoke_${timestamp}"\nch_target="${CLICKHOUSE_DATABASE}_restore_smoke_${timestamp}"\n\necho "==> PostgreSQL restore smoke test"\n"$SCRIPT_DIR/restore-postgres.sh" \\\n  --database "$POSTGRES_DATABASE" \\\n  --target "$pg_target"\ncleanup_postgres="$pg_target"\n\necho "==> ClickHouse restore smoke test"\n"$SCRIPT_DIR/restore-clickhouse.sh" \\\n  --source-db "$CLICKHOUSE_DATABASE" \\\n  --target-db "$ch_target"\ncleanup_clickhouse="$ch_target"\n\necho "==> Redis restore verification"\n"$SCRIPT_DIR/restore-redis.sh" --mode verify\n\nif [ -n "$MINIO_BUCKET" ]; then\n  echo "==> MinIO restore smoke test"\n  "$SCRIPT_DIR/restore-minio.sh" \\\n    --bucket "$MINIO_BUCKET" \\\n    --target-bucket "${MINIO_BUCKET}-restore-smoke-${timestamp}"\nelse\n  echo "==> MINIO_BUCKET is unset; skipping MinIO restore smoke test"\nfi\n\ncat <<EOF\n\nRestore smoke tests completed.\n\nTemporary databases were intentionally retained for inspection:\n  PostgreSQL: $cleanup_postgres\n  ClickHouse: $cleanup_clickhouse\n\nDelete after inspection:\n\n  kubectl -n data exec statefulset/postgres -- \\\n    dropdb --username postgres "$cleanup_postgres"\n\n  kubectl -n data exec statefulset/clickhouse -- \\\n    clickhouse-client --query \\\n    \'DROP DATABASE IF EXISTS \\`$cleanup_clickhouse\\`\'\nEOF\n'}, 'sops-check.sh': {'interpreter': 'sh', 'body': 'set -eu\n\ndie() {\n  printf \'error: %s\\n\' "$*" >&2\n  exit 1\n}\n\ncommand -v sops >/dev/null 2>&1 || die "sops is required"\n[ -f .sops.yaml ] || die ".sops.yaml is missing; run ./scripts/sops-init.sh"\n\ncase "$(grep -E \'^[[:space:]]*age:[[:space:]]*age1\' .sops.yaml | wc -l | tr -d \' \')" in\n  0) die ".sops.yaml does not contain an age recipient" ;;\nesac\n\nfailed=0\nfound=0\n\n# Git-tracked secret manifests only. Examples and Helm templates are excluded.\nfiles="$(\n  git ls-files \\\n    \'*secret.yaml\' \\\n    \'*secret.yml\' \\\n    \'*.secret.yaml\' \\\n    \'*.secret.yml\' \\\n  | grep -Ev \\\n      \'(^|/)(examples?|templates?)/|[.]example([.]|$)|secret-example[.]ya?ml$\' \\\n  || true\n)"\n\nfor file in $files; do\n  found=$((found + 1))\n\n  if ! grep -q \'^kind:[[:space:]]*Secret[[:space:]]*$\' "$file"; then\n    printf \'not a Kubernetes Secret: %s\\n\' "$file" >&2\n    failed=1\n    continue\n  fi\n\n  if ! grep -q \'^sops:[[:space:]]*$\' "$file"; then\n    printf \'missing SOPS metadata: %s\\n\' "$file" >&2\n    failed=1\n    continue\n  fi\n\n  if ! grep -q \'ENC\\[AES256_GCM\' "$file"; then\n    printf \'plaintext or malformed SOPS secret: %s\\n\' "$file" >&2\n    failed=1\n    continue\n  fi\n\n  # MAC/decryption validation. Does not print plaintext.\n  if ! sops --decrypt "$file" >/dev/null; then\n    printf \'cannot decrypt or authenticate: %s\\n\' "$file" >&2\n    failed=1\n    continue\n  fi\n\n  printf \'ok: %s\\n\' "$file"\ndone\n\nif [ "$found" -eq 0 ]; then\n  printf \'warning: no tracked production *.secret.yaml files found\\n\' >&2\nfi\n\n[ "$failed" -eq 0 ] || die "SOPS validation failed"\n'}, 'sops-create-app-secret.sh': {'interpreter': 'sh', 'body': 'set -eu\n\nENV_FILE="${1:-}"\nOUTPUT="${2:-clusters/production/casinoshiz/casinoshiz.secret.yaml}"\nNAMESPACE="${NAMESPACE:-casinoshiz}"\nNAME="${NAME:-casinoshiz-secrets}"\n\ndie() {\n  printf \'error: %s\\n\' "$*" >&2\n  exit 1\n}\n\ncommand -v kubectl >/dev/null 2>&1 || die "kubectl is required"\ncommand -v sops >/dev/null 2>&1 || die "sops is required"\n[ -f .sops.yaml ] || die ".sops.yaml missing; run ./scripts/sops-init.sh"\n[ -n "$ENV_FILE" ] || die "usage: $0 path/to/production.env [output.secret.yaml]"\n[ -f "$ENV_FILE" ] || die "env file not found: $ENV_FILE"\n\nmkdir -p "$(dirname "$OUTPUT")"\n\nkubectl create secret generic "$NAME" \\\n  --namespace "$NAMESPACE" \\\n  --from-env-file="$ENV_FILE" \\\n  --dry-run=client \\\n  -o yaml > "$OUTPUT"\n\nsops --encrypt --in-place "$OUTPUT"\nprintf \'created encrypted application secret: %s\\n\' "$OUTPUT"\n'}, 'sops-create-ghcr-secret.sh': {'interpreter': 'sh', 'body': 'set -eu\n\nNAMESPACE="${NAMESPACE:-casinoshiz}"\nNAME="${NAME:-ghcr-pull}"\nOUTPUT="${OUTPUT:-clusters/production/casinoshiz/ghcr.secret.yaml}"\nGHCR_SERVER="${GHCR_SERVER:-ghcr.io}"\n\ndie() {\n  printf \'error: %s\\n\' "$*" >&2\n  exit 1\n}\n\ncommand -v kubectl >/dev/null 2>&1 || die "kubectl is required"\ncommand -v sops >/dev/null 2>&1 || die "sops is required"\n[ -f .sops.yaml ] || die ".sops.yaml missing; run ./scripts/sops-init.sh"\n[ -n "${GHCR_USERNAME:-}" ] || die "GHCR_USERNAME is required"\n[ -n "${GHCR_TOKEN:-}" ] || die "GHCR_TOKEN is required"\n\nmkdir -p "$(dirname "$OUTPUT")"\n\nkubectl create secret docker-registry "$NAME" \\\n  --namespace "$NAMESPACE" \\\n  --docker-server "$GHCR_SERVER" \\\n  --docker-username "$GHCR_USERNAME" \\\n  --docker-password "$GHCR_TOKEN" \\\n  --dry-run=client \\\n  -o yaml > "$OUTPUT"\n\nsops --encrypt --in-place "$OUTPUT"\nunset GHCR_TOKEN\n\nprintf \'created encrypted GHCR pull secret: %s\\n\' "$OUTPUT"\n'}, 'sops-encrypt.sh': {'interpreter': 'sh', 'body': 'set -eu\n\ndie() {\n  printf \'error: %s\\n\' "$*" >&2\n  exit 1\n}\n\ncommand -v sops >/dev/null 2>&1 || die "sops is required"\n[ -f .sops.yaml ] || die ".sops.yaml is missing; run ./scripts/sops-init.sh"\n\n[ "$#" -gt 0 ] || {\n  cat <<\'EOF\'\nUsage:\n  ./scripts/sops-encrypt.sh path/to/file.secret.yaml [...]\n\nEach file must be a Kubernetes Secret YAML containing data or stringData.\nThe file is encrypted in place after validation.\nEOF\n  exit 2\n}\n\nfor file in "$@"; do\n  [ -f "$file" ] || die "file not found: $file"\n\n  kind="$(awk \'$1 == "kind:" { print $2; exit }\' "$file")"\n  [ "$kind" = Secret ] || die "$file is not a Kubernetes Secret"\n\n  if grep -q \'ENC\\[AES256_GCM\' "$file"; then\n    printf \'already encrypted: %s\\n\' "$file"\n    continue\n  fi\n\n  sops --encrypt --in-place "$file"\n  grep -q \'ENC\\[AES256_GCM\' "$file" ||\n    die "encryption marker not found after encrypting $file"\n\n  printf \'encrypted: %s\\n\' "$file"\ndone\n'}, 'sops-init.sh': {'interpreter': 'sh', 'body': 'set -eu\n\nAGE_KEY_FILE="${AGE_KEY_FILE:-$HOME/.config/sops/age/keys.txt}"\nOUTPUT="${OUTPUT:-.sops.yaml}"\n\ndie() {\n  printf \'error: %s\\n\' "$*" >&2\n  exit 1\n}\n\ncommand -v age-keygen >/dev/null 2>&1 || die "age-keygen is required"\ncommand -v sops >/dev/null 2>&1 || die "sops is required"\n\nif [ ! -f "$AGE_KEY_FILE" ]; then\n  mkdir -p "$(dirname "$AGE_KEY_FILE")"\n  chmod 700 "$(dirname "$AGE_KEY_FILE")"\n  age-keygen -o "$AGE_KEY_FILE"\n  chmod 600 "$AGE_KEY_FILE"\nfi\n\nrecipient="$(age-keygen -y "$AGE_KEY_FILE")"\ncase "$recipient" in\n  age1*) ;;\n  *) die "invalid age recipient derived from $AGE_KEY_FILE" ;;\nesac\n\ncat > "$OUTPUT" <<EOF\ncreation_rules:\n  - path_regex: \'(^|/).*[.]secret[.]ya?ml$\'\n    encrypted_regex: \'^(data|stringData)$\'\n    age: $recipient\n\n  - path_regex: \'(^|/).*ghcr.*[.]ya?ml$\'\n    encrypted_regex: \'^(data|stringData)$\'\n    age: $recipient\nEOF\n\nprintf \'created %s for recipient %s\\n\' "$OUTPUT" "$recipient"\nprintf \'private identity remains at %s\\n\' "$AGE_KEY_FILE"\n'}}

COMMANDS = {('cluster', 'status'): ('cluster-status.sh', []), ('cluster', 'preflight'): ('preflight.sh', []), ('cluster', 'post-deploy'): ('post-deploy-check.sh', []), ('backup', 'run'): ('manual-backup.sh', []), ('restore', 'postgres'): ('restore-postgres.sh', None), ('restore', 'clickhouse'): ('restore-clickhouse.sh', None), ('restore', 'redis'): ('restore-redis.sh', None), ('restore', 'minio'): ('restore-minio.sh', None), ('restore', 'smoke'): ('restore-smoke-test.sh', []), ('sops', 'init'): ('sops-init.sh', None), ('sops', 'encrypt'): ('sops-encrypt.sh', None), ('sops', 'check'): ('sops-check.sh', []), ('sops', 'app-secret'): ('sops-create-app-secret.sh', None), ('sops', 'ghcr-secret'): ('sops-create-ghcr-secret.sh', []), ('local', 'create'): ('local-cluster-create.sh', []), ('local', 'delete'): ('local-cluster-delete.sh', []), ('local', 'argocd-bootstrap'): ('local-argocd-bootstrap.sh', []), ('local', 'image-push'): ('local-image-push.sh', None)}


class InfraError(RuntimeError):
    pass


def die(message: str) -> NoReturn:
    raise InfraError(message)


def execute(script_name: str, forwarded: list[str]) -> int:
    spec = SCRIPTS[script_name]
    interpreter = spec["interpreter"]
    suffix = ".bash" if interpreter == "bash" else ".sh"

    # A temporary file preserves $0, positional arguments, heredocs,
    # process substitution for bash scripts, and source-independent behavior.
    with tempfile.NamedTemporaryFile(
        mode="w",
        encoding="utf-8",
        suffix=suffix,
        prefix="casinoshiz-infra-",
        delete=False,
    ) as stream:
        stream.write(f"#!/usr/bin/env {interpreter}\n")
        stream.write(spec["body"])
        temp_path = Path(stream.name)

    try:
        temp_path.chmod(0o700)
        completed = subprocess.run(
            [interpreter, str(temp_path), *forwarded],
            cwd=ROOT,
            env=os.environ.copy(),
            check=False,
        )
        return completed.returncode
    finally:
        temp_path.unlink(missing_ok=True)


def passthrough_parser(name: str, help_text: str) -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        prog=f"infra.py {name}",
        description=help_text,
        add_help=False,
    )
    parser.add_argument("-h", "--help", action="store_true")
    parser.add_argument("args", nargs=argparse.REMAINDER)
    return parser


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        description="CasinoShiz infrastructure operations",
    )
    groups = parser.add_subparsers(dest="group", required=True)

    descriptions = {
        "cluster": "Cluster preflight, status and post-deployment checks",
        "backup": "Run backup operations",
        "restore": "Restore and restore-verification operations",
        "sops": "SOPS/age initialization, encryption and Secret creation",
        "local": "Local k3d and Argo CD helpers",
    }

    commands = {
        "cluster": {
            "status": "Show cluster status",
            "preflight": "Run production preflight",
            "post-deploy": "Run post-deployment checks",
        },
        "backup": {
            "run": "Run all backup CronJobs immediately",
        },
        "restore": {
            "postgres": "Restore PostgreSQL into a separate database by default",
            "clickhouse": "Restore ClickHouse into a separate database by default",
            "redis": "Verify or replace Redis from backup",
            "minio": "Restore a MinIO bucket",
            "smoke": "Run safe restore smoke tests",
        },
        "sops": {
            "init": "Create the age identity and .sops.yaml",
            "encrypt": "Encrypt Kubernetes Secret manifests in place",
            "check": "Validate tracked SOPS Secret manifests",
            "app-secret": "Create encrypted application Secret from env file",
            "ghcr-secret": "Create encrypted GHCR pull Secret",
        },
        "local": {
            "create": "Create local k3d cluster and registry",
            "delete": "Delete local k3d cluster",
            "argocd-bootstrap": "Install Argo CD locally and configure SOPS",
            "image-push": "Push an image to the local registry",
        },
    }

    for group, group_help in descriptions.items():
        group_parser = groups.add_parser(group, help=group_help)
        sub = group_parser.add_subparsers(dest="command", required=True)
        for command, command_help in commands[group].items():
            command_parser = sub.add_parser(
                command,
                help=command_help,
                add_help=False,
            )
            command_parser.add_argument("-h", "--help", action="store_true")
            command_parser.add_argument("args", nargs=argparse.REMAINDER)

    return parser


def legacy_help(script_name: str) -> int:
    # Most legacy operations already expose useful --help. Commands without
    # one are documented by the unified parser and execute only when requested.
    return execute(script_name, ["--help"])


def main() -> int:
    parser = build_parser()
    ns, unknown = parser.parse_known_args()

    key = (ns.group, ns.command)
    script_name, fixed_args = COMMANDS[key]

    if ns.help:
        if key in {
            ("restore", "postgres"),
            ("restore", "clickhouse"),
            ("restore", "redis"),
            ("restore", "minio"),
            ("sops", "encrypt"),
            ("sops", "app-secret"),
            ("local", "image-push"),
        }:
            return legacy_help(script_name)

        parser.print_help()
        return 0

    forwarded = [*ns.args, *unknown]

    if fixed_args is not None:
        forwarded = [*fixed_args, *forwarded]

    return execute(script_name, forwarded)


if __name__ == "__main__":
    try:
        raise SystemExit(main())
    except (InfraError, KeyboardInterrupt) as exc:
        print(f"error: {exc}", file=sys.stderr)
        raise SystemExit(1)
